val clazz = classLoader.loadClass(PAYLOAD_CLASS)
val instance = clazz.getDeclaredConstructor().newInstance() as? DynamicEntry

// --- RESOURCE INJECTION --- 
// We force the Shell's AssetManager to include our dynamic DEX file
// because the DEX file *is* technically an APK structure once we add resources to it.
try {
    val assetManager = context.assets
    val addAssetPath = assetManager.javaClass.getMethod("addAssetPath", String::class.java)
    addAssetPath.invoke(assetManager, internalDex.absolutePath)
} catch (e: Exception) { 
    e.printStackTrace() 
}

